-- Tạo generated tsvector column (PostgreSQL 12+)
ALTER TABLE products ADD COLUMN search_vector tsvector
    GENERATED ALWAYS AS (
        to_tsvector('english',
            coalesce(name, '') || ' ' ||
            coalesce(description, '') || ' ' ||
            coalesce(category, ''))
    ) STORED;

-- GIN index
CREATE INDEX idx_products_search ON products USING GIN (search_vector);

-- Search
SELECT id, name, ts_rank(search_vector, query) AS rank
FROM products, to_tsquery('english', 'laptop & wireless') query
WHERE search_vector @@ query
ORDER BY rank DESC
LIMIT 20;

-- Phrase search
SELECT * FROM products
WHERE search_vector @@ phraseto_tsquery('english', 'gaming laptop');

-- Highlight kết quả
SELECT name, ts_headline('english', description,
    to_tsquery('laptop'), 'MaxFragments=2, ShortWord=3') AS snippet
FROM products WHERE search_vector @@ to_tsquery('laptop');

-- Vietnamese (cần unaccent + custom config)
CREATE TEXT SEARCH CONFIGURATION vietnamese (COPY = simple);
ALTER TEXT SEARCH CONFIGURATION vietnamese
    ALTER MAPPING FOR hword, hword_part, word WITH unaccent, simple;

-- Fuzzy search với pg_trgm extension
CREATE EXTENSION pg_trgm;
SELECT * FROM products WHERE name % 'labtop'; -- typo tolerance
